import json, os, requests, datetime

WATCHED_SKUS = [
    {"sku": "Standard_D4s_v5", "region": "eastus", "os": "Linux"},
    {"sku": "Standard_D8s_v5", "region": "eastus", "os": "Linux"},
    {"sku": "Standard_E4s_v5", "region": "eastus", "os": "Linux"},
]
BASELINE_FILE = "/tmp/azure-price-baseline.json"

def get_payg_price(sku, region, os_type):
    params = {
        "api-version": "2023-01-01-preview",
        "$filter": (
            f"armSkuName eq 'Standard_{sku}' and armRegionName eq '{region}' "
            f"and priceType eq 'Consumption' and contains(productName, '{os_type}') "
            f"and not contains(skuName, 'Spot')"
        ),
    }
    items = requests.get(
        "https://prices.azure.com/api/retail/prices", params=params, timeout=10
    ).json().get("Items", [])
    return items[0]["retailPrice"] if items else 0

# Load baseline
baseline = {}
if os.path.exists(BASELINE_FILE):
    with open(BASELINE_FILE) as f:
        baseline = json.load(f)

current = {}
changes = []
for watch in WATCHED_SKUS:
    key = f"{watch['sku']}:{watch['region']}:{watch['os']}"
    price = get_payg_price(watch["sku"], watch["region"], watch["os"])
    current[key] = price

    if key in baseline and baseline[key] != price:
        pct = (price - baseline[key]) / baseline[key] * 100
        changes.append(f"PRICE CHANGE: {key}: ${baseline[key]:.4f} -> ${price:.4f} ({pct:+.2f}%)")

# Save current as new baseline
with open(BASELINE_FILE, "w") as f:
    json.dump(current, f, indent=2)

if changes:
    print(f"[{datetime.date.today()}] Azure price changes detected:")
    for c in changes:
        print(f"  {c}")
else:
    print(f"[{datetime.date.today()}] No price changes detected for {len(WATCHED_SKUS)} watched SKUs.")

